import React, { useState, useEffect } from "react";
import axios from "axios";
import "./ModelAccuracy.css";

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  LabelList
} from "recharts";

function ModelAccuracy() {
  const [modelData, setModelData] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5050/model-performance")
      .then(res => {
        console.log(res.data);
        setModelData(res.data.allModels);
      })
      .catch(err => console.error(err));
  }, []);

  // 🔥 Get best accuracy
  const maxAccuracy = Math.max(...modelData.map(m => m.accuracy || 0));

  return (
    <div className="model-container">

      {/* TITLE */}
      <h2>MODEL PERFORMANCE COMPARISON: SALARY PREDICTION SYSTEM</h2>
      <p>Comparing ML Models across Key Metrics for Accuracy and Error</p>

      {/* CHART */}
      <div className="chart-wrapper">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={modelData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
            <XAxis dataKey="name" stroke="#cbd5f5" />
            <YAxis domain={[0, 1]} stroke="#cbd5f5" />
            <Tooltip />
            <Legend />

            {/* Accuracy */}
            <Bar dataKey="accuracy" fill="#f59e0b" name="Accuracy (R²)">
              <LabelList dataKey="accuracy" position="top" />
            </Bar>

            {/* RMSE */}
            <Bar dataKey="rmse" fill="#3b82f6" name="RMSE">
              <LabelList dataKey="rmse" position="top" />
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* TABLE */}
      <table className="model-table">
        <thead>
          <tr>
            <th>Model</th>
            <th>Accuracy (R²)</th>
            <th>RMSE</th>
          </tr>
        </thead>

        <tbody>
          {modelData.map((model, idx) => (
            <tr
              key={idx}
              className={model.accuracy === maxAccuracy ? "best-model" : ""}
            >
              <td>{model.name}</td>
              <td>{model.accuracy}</td>
              <td>{model.rmse}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* FOOTER */}
      <p className="note">
        Note: RMSE is scaled to 0-1 for direct visual comparison with R² Accuracy.
      </p>

    </div>
  );
}

export default ModelAccuracy;
